import React from "react";
import { useCart } from "./CartContext";

function Help() {
  const {
    cartItems,
    addToCart,
    increaseQty,
    decreaseQty
  } = useCart();

  // SERVICES LIST
  const services = [
    "Medicines",
    "Groceries",
    "Emergency",
    "Food Delivery",
    "Transport"
  ];

  // MEDICINES LIST (ID MUST MATCH DB)
  const medicines = [
    { id: 1, name: "Paracetamol" },
    { id: 2, name: "Ibuprofen" },
    { id: 3, name: "Amoxicillin" },
    { id: 4, name: "Cetirizine" },
    { id: 5, name: "Vitamin C" }
  ];

  // GET QUANTITY
  const getQty = (id) => {
    const item = cartItems.find((i) => i.id === id);
    return item ? item.quantity : 0;
  };

  return (
    <div className="help-container">

      <h2>Select Service</h2>

      {/* SERVICES GRID */}
      <div className="services">
        {services.map((service) => (
          <div key={service} className="service-card">

            <h3>{service}</h3>

            {service !== "Medicines" ? (
              <p style={{ color: "gray" }}>Under Maintenance 🚧</p>
            ) : (
              <p style={{ color: "green" }}>Available</p>
            )}

          </div>
        ))}
      </div>

      {/* MEDICINES SECTION */}
      <h2 style={{ marginTop: "30px" }}>Medicines</h2>

      <div className="medicine-list">

        {medicines.map((med) => {
          const qty = getQty(med.id);

          return (
            <div key={med.id} className="medicine-row">

              <span>{med.name}</span>

              {qty === 0 ? (
                <button
                  className="add-btn"
                  onClick={() => addToCart(med)}
                >
                  Add
                </button>
              ) : (
                <div className="qty-controls">
                  <button onClick={() => decreaseQty(med.id)}>-</button>
                  <span>{qty}</span>
                  <button
                    onClick={() => increaseQty(med.id)}
                    disabled={qty >= 5}
                  >
                    +
                  </button>
                </div>
              )}

            </div>
          );
        })}

      </div>

    </div>
  );
}

export default Help;
